-- ============================================================
--  DATAMART RAPPI - LOS OLIVOS
--  Proyecto: Construcción de un Datamart para optimizar
--            el reparto de comida de Rappi en Los Olivos
--  Curso   : Inteligencia de Negocios
--  Grupo   : 2
-- ============================================================

CREATE DATABASE IF NOT EXISTS datamart_rappi
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_spanish_ci;

USE datamart_rappi;

SET FOREIGN_KEY_CHECKS = 0;

-- ============================================================
--  DIMENSIONES BASE (sin dependencias)
-- ============================================================

DROP TABLE IF EXISTS dim_zona;
CREATE TABLE dim_zona (
  id_zona          INT          NOT NULL,
  distrito         VARCHAR(60)  NOT NULL,
  cuadrante_mapa   VARCHAR(20)  NOT NULL,
  avenida_principal VARCHAR(80) NOT NULL,
  PRIMARY KEY (id_zona)
) ENGINE=InnoDB COMMENT='Zonas geográficas de Los Olivos';

DROP TABLE IF EXISTS dim_categoria_comida;
CREATE TABLE dim_categoria_comida (
  id_categoria    INT         NOT NULL,
  nombre_categoria VARCHAR(60) NOT NULL,
  descripcion      VARCHAR(120),
  PRIMARY KEY (id_categoria)
) ENGINE=InnoDB COMMENT='Categorías de tipo de comida';

DROP TABLE IF EXISTS dim_tipo_vehiculo;
CREATE TABLE dim_tipo_vehiculo (
  id_tipo_vehiculo INT         NOT NULL,
  descripcion      VARCHAR(40) NOT NULL,
  PRIMARY KEY (id_tipo_vehiculo)
) ENGINE=InnoDB COMMENT='Tipo de vehículo del repartidor';

DROP TABLE IF EXISTS dim_tipo_suscripcion;
CREATE TABLE dim_tipo_suscripcion (
  id_suscripcion      INT            NOT NULL,
  nombre_suscripcion  VARCHAR(40)    NOT NULL,
  costo_mensual_soles DECIMAL(6,2)   NOT NULL DEFAULT 0,
  envio_gratis        TINYINT(1)     NOT NULL DEFAULT 0,
  beneficios          VARCHAR(120),
  PRIMARY KEY (id_suscripcion)
) ENGINE=InnoDB COMMENT='Planes de suscripción Rappi';

DROP TABLE IF EXISTS dim_metodo_pago;
CREATE TABLE dim_metodo_pago (
  id_metodo  INT         NOT NULL,
  tipo_pago  VARCHAR(40) NOT NULL,
  plataforma VARCHAR(30) NOT NULL,
  PRIMARY KEY (id_metodo)
) ENGINE=InnoDB COMMENT='Métodos de pago disponibles';

DROP TABLE IF EXISTS dim_estado_pedido;
CREATE TABLE dim_estado_pedido (
  id_estado        INT          NOT NULL,
  estado_actual    VARCHAR(40)  NOT NULL,
  detalle_estado   VARCHAR(120),
  responsable_actual VARCHAR(30),
  hubo_incidencia  TINYINT(1)   NOT NULL DEFAULT 0,
  PRIMARY KEY (id_estado)
) ENGINE=InnoDB COMMENT='Estados posibles de un pedido';

-- ============================================================
--  DIMENSIONES CON DEPENDENCIAS
-- ============================================================

DROP TABLE IF EXISTS dim_cadena_restaurante;
CREATE TABLE dim_cadena_restaurante (
  id_cadena          INT         NOT NULL,
  nombre_cadena      VARCHAR(60) NOT NULL,
  tiene_sucursal_vip TINYINT(1)  NOT NULL DEFAULT 0,
  id_categoria       INT         NOT NULL,
  PRIMARY KEY (id_cadena),
  CONSTRAINT fk_cadena_categoria
    FOREIGN KEY (id_categoria) REFERENCES dim_categoria_comida(id_categoria)
) ENGINE=InnoDB COMMENT='Cadenas de restaurantes aliados';

DROP TABLE IF EXISTS dim_restaurante;
CREATE TABLE dim_restaurante (
  id_restaurante       INT           NOT NULL,
  nombre_sucursal      VARCHAR(80)   NOT NULL,
  latitud              DECIMAL(9,6)  NOT NULL,
  longitud             DECIMAL(9,6)  NOT NULL,
  calificacion_promedio DECIMAL(3,1),
  id_cadena            INT           NOT NULL,
  PRIMARY KEY (id_restaurante),
  CONSTRAINT fk_restaurante_cadena
    FOREIGN KEY (id_cadena) REFERENCES dim_cadena_restaurante(id_cadena)
) ENGINE=InnoDB COMMENT='Sucursales de restaurantes en Los Olivos';

DROP TABLE IF EXISTS dim_repartidor;
CREATE TABLE dim_repartidor (
  id_repartidor          INT           NOT NULL,
  modalidad_reparto      VARCHAR(20)   NOT NULL,
  calificacion_repartidor DECIMAL(3,1),
  id_tipo_vehiculo       INT           NOT NULL,
  PRIMARY KEY (id_repartidor),
  CONSTRAINT fk_repartidor_vehiculo
    FOREIGN KEY (id_tipo_vehiculo) REFERENCES dim_tipo_vehiculo(id_tipo_vehiculo)
) ENGINE=InnoDB COMMENT='Repartidores activos en Los Olivos';

DROP TABLE IF EXISTS dim_cliente;
CREATE TABLE dim_cliente (
  id_cliente               INT         NOT NULL,
  frecuencia_compra        VARCHAR(20) NOT NULL,
  id_suscripcion           INT         NOT NULL,
  id_metodo_pago_frecuente INT         NOT NULL,
  PRIMARY KEY (id_cliente),
  CONSTRAINT fk_cliente_suscripcion
    FOREIGN KEY (id_suscripcion) REFERENCES dim_tipo_suscripcion(id_suscripcion),
  CONSTRAINT fk_cliente_metodo
    FOREIGN KEY (id_metodo_pago_frecuente) REFERENCES dim_metodo_pago(id_metodo)
) ENGINE=InnoDB COMMENT='Clientes registrados en Rappi';

DROP TABLE IF EXISTS dim_tiempo;
CREATE TABLE dim_tiempo (
  id_tiempo    INT         NOT NULL,
  fecha        DATE        NOT NULL,
  hora_dia     TINYINT     NOT NULL COMMENT '0-23',
  franja       VARCHAR(15) NOT NULL COMMENT 'Mañana/Tarde/Noche/Madrugada',
  dia_semana   VARCHAR(15) NOT NULL,
  mes          TINYINT     NOT NULL,
  anio         SMALLINT    NOT NULL,
  es_hora_pico TINYINT(1)  NOT NULL DEFAULT 0,
  PRIMARY KEY (id_tiempo),
  INDEX idx_fecha (fecha),
  INDEX idx_franja (franja)
) ENGINE=InnoDB COMMENT='Dimensión temporal de pedidos';

-- ============================================================
--  TABLA DE HECHOS
-- ============================================================

DROP TABLE IF EXISTS fact_pedidos;
CREATE TABLE fact_pedidos (
  id_pedido              INT            NOT NULL,
  id_tiempo              INT            NOT NULL,
  id_zona                INT            NOT NULL,
  id_restaurante         INT            NOT NULL,
  id_repartidor          INT            NOT NULL,
  id_cliente             INT            NOT NULL,
  id_estado              INT            NOT NULL,
  -- Métricas
  tiempo_total_min       DECIMAL(6,1)   NOT NULL COMMENT 'Tiempo real de entrega en minutos',
  dist_asignacion_km     DECIMAL(6,3)   NOT NULL COMMENT 'Distancia repartidor-restaurante al asignar',
  dist_entrega_km        DECIMAL(6,3)   NOT NULL COMMENT 'Distancia restaurante-cliente',
  tiempo_espera_rest_min DECIMAL(6,1)   NOT NULL COMMENT 'Minutos que esperó el repartidor en el local',
  cumple_sla             TINYINT(1)     NOT NULL COMMENT '1=cumple SLA de 30min, 0=incumple',
  minutos_retraso        DECIMAL(6,1)   NOT NULL DEFAULT 0 COMMENT 'Minutos de retraso sobre el SLA',
  valor_pedido_soles     DECIMAL(8,2)   NOT NULL,
  PRIMARY KEY (id_pedido),
  CONSTRAINT fk_fact_tiempo      FOREIGN KEY (id_tiempo)      REFERENCES dim_tiempo(id_tiempo),
  CONSTRAINT fk_fact_zona        FOREIGN KEY (id_zona)        REFERENCES dim_zona(id_zona),
  CONSTRAINT fk_fact_restaurante FOREIGN KEY (id_restaurante) REFERENCES dim_restaurante(id_restaurante),
  CONSTRAINT fk_fact_repartidor  FOREIGN KEY (id_repartidor)  REFERENCES dim_repartidor(id_repartidor),
  CONSTRAINT fk_fact_cliente     FOREIGN KEY (id_cliente)     REFERENCES dim_cliente(id_cliente),
  CONSTRAINT fk_fact_estado      FOREIGN KEY (id_estado)      REFERENCES dim_estado_pedido(id_estado),
  INDEX idx_sla        (cumple_sla),
  INDEX idx_zona_tiempo (id_zona, id_tiempo),
  INDEX idx_restaurante (id_restaurante)
) ENGINE=InnoDB COMMENT='Tabla de hechos: un registro por pedido';

SET FOREIGN_KEY_CHECKS = 1;

-- ============================================================
--  CARGA DE DATOS - DIMENSIONES BASE
-- ============================================================

-- dim_zona

-- dim_categoria_comida

-- dim_tipo_vehiculo

