-- ============================================================
--  CONSULTAS KPI - Verificación del Datamart
-- ============================================================

-- KPI 1: Cumplimiento de SLA general
SELECT
  ROUND(SUM(cumple_sla) / COUNT(*) * 100, 2) AS pct_cumplimiento_sla,
  COUNT(*)                                    AS total_pedidos,
  SUM(cumple_sla)                             AS pedidos_a_tiempo,
  COUNT(*) - SUM(cumple_sla)                  AS pedidos_fuera_sla
FROM fact_pedidos;

-- KPI 2: Tiempo promedio de retraso (solo pedidos que incumplen)
SELECT
  ROUND(AVG(minutos_retraso), 2) AS retraso_promedio_min,
  MAX(minutos_retraso)           AS retraso_maximo_min,
  COUNT(*)                       AS pedidos_con_retraso
FROM fact_pedidos
WHERE cumple_sla = 0;

-- KPI 3: Distancia promedio de asignación
SELECT
  ROUND(AVG(dist_asignacion_km), 3) AS distancia_prom_km,
  ROUND(MIN(dist_asignacion_km), 3) AS distancia_min_km,
  ROUND(MAX(dist_asignacion_km), 3) AS distancia_max_km
FROM fact_pedidos;

-- KPI 4: Tiempo promedio de espera en restaurante
SELECT
  ROUND(AVG(tiempo_espera_rest_min), 2) AS espera_prom_min
FROM fact_pedidos;

-- KPI 5: Tiempo promedio de entrega por franja horaria
SELECT
  t.franja,
  COUNT(*)                               AS total_pedidos,
  ROUND(AVG(f.tiempo_total_min), 2)      AS tiempo_prom_min,
  ROUND(AVG(f.cumple_sla) * 100, 1)      AS pct_sla
FROM fact_pedidos f
JOIN dim_tiempo t ON f.id_tiempo = t.id_tiempo
GROUP BY t.franja
ORDER BY tiempo_prom_min DESC;

-- EXTRA: Cumplimiento SLA por zona
SELECT
  z.cuadrante_mapa,
  z.avenida_principal,
  COUNT(*)                               AS total_pedidos,
  ROUND(AVG(f.cumple_sla) * 100, 1)      AS pct_sla,
  ROUND(AVG(f.tiempo_total_min), 1)      AS tiempo_prom_min
FROM fact_pedidos f
JOIN dim_zona z ON f.id_zona = z.id_zona
GROUP BY z.id_zona, z.cuadrante_mapa, z.avenida_principal
ORDER BY pct_sla ASC;

-- EXTRA: Restaurantes con mayor tiempo de espera
SELECT
  r.nombre_sucursal,
  c.nombre_cadena,
  COUNT(*)                               AS total_pedidos,
  ROUND(AVG(f.tiempo_espera_rest_min),1) AS espera_prom_min,
  ROUND(AVG(f.cumple_sla)*100, 1)        AS pct_sla
FROM fact_pedidos f
JOIN dim_restaurante r    ON f.id_restaurante = r.id_restaurante
JOIN dim_cadena_restaurante c ON r.id_cadena = c.id_cadena
GROUP BY r.id_restaurante, r.nombre_sucursal, c.nombre_cadena
ORDER BY espera_prom_min DESC;

-- EXTRA: Repartidores con más incumplimientos
SELECT
  f.id_repartidor,
  rep.modalidad_reparto,
  veh.descripcion                         AS vehiculo,
  COUNT(*)                                AS total_pedidos,
  SUM(CASE WHEN f.cumple_sla = 0 THEN 1 ELSE 0 END) AS incumplimientos,
  ROUND(AVG(f.dist_asignacion_km), 2)    AS dist_asig_prom_km
FROM fact_pedidos f
JOIN dim_repartidor rep ON f.id_repartidor = rep.id_repartidor
JOIN dim_tipo_vehiculo veh ON rep.id_tipo_vehiculo = veh.id_tipo_vehiculo
GROUP BY f.id_repartidor, rep.modalidad_reparto, veh.descripcion
HAVING total_pedidos >= 5
ORDER BY incumplimientos DESC
LIMIT 20;